      <h1>All Questions</h1>
      {/* <QuestionList /> */}
      <p style={{ color: 'green', fontSize: '20px' }}>
        QuestionList is temporarily disabled — if you see this green text, the crash is inside QuestionList.
      </p>
    </div>
  );
};

export default Home;
